SOLUTION:

def isPrime(n: Int): Boolean = {
  if (n <= 1) false
  else {
    def isPrimeHelper(n: Int, i: Int): Boolean = {
      if (i * i > n) true
      else if (n % i == 0) false
      else isPrimeHelper(n, i + 1)
    }
    isPrimeHelper(n, 2)
  }
}

